import{_ as s,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Politique de Confidentialité : Comprendre la Protection des Données | OpenCodeDocs","description":"Découvrez la politique de confidentialité d'OpenCodeDocs et ses mesures de protection des données. Comment nous collectons, utilisons et stockons vos informations personnelles, et vos droits sur vos données.","frontmatter":{"title":"Politique de Confidentialité : Comprendre la Protection des Données | OpenCodeDocs","sidebarTitle":"Où vont vos données ?","subtitle":"Politique de Confidentialité : Comprendre la Protection des Données","description":"Découvrez la politique de confidentialité d'OpenCodeDocs et ses mesures de protection des données. Comment nous collectons, utilisons et stockons vos informations personnelles, et vos droits sur vos données."},"headers":[],"relativePath":"fr/privacy.md","filePath":"fr/privacy.md"}`),n={name:"fr/privacy.md"};function r(a,e,l,u,d,c){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="politique-de-confidentialite" tabindex="-1">Politique de Confidentialité <a class="header-anchor" href="#politique-de-confidentialite" aria-label="Permalink to &quot;Politique de Confidentialité&quot;">​</a></h1><p>Dernière mise à jour : 2026-01-01</p><p>Merci d&#39;utiliser OpenCodeDocs. Nous accordons une grande importance à votre vie privée et à la protection de vos informations personnelles. Cette politique de confidentialité vous aidera à comprendre comment nous collectons, utilisons, stockons et protégeons vos informations personnelles.</p><h2 id="_1-informations-que-nous-collectons" tabindex="-1">1. Informations que nous collectons <a class="header-anchor" href="#_1-informations-que-nous-collectons" aria-label="Permalink to &quot;1. Informations que nous collectons&quot;">​</a></h2><p>Lorsque vous utilisez les services d&#39;OpenCodeDocs, nous pouvons collecter les types d&#39;informations suivants :</p><h3 id="informations-de-compte" tabindex="-1">Informations de compte <a class="header-anchor" href="#informations-de-compte" aria-label="Permalink to &quot;Informations de compte&quot;">​</a></h3><ul><li><strong>Adresse e-mail</strong> : Utilisée pour l&#39;inscription au compte, la vérification de connexion et les notifications importantes</li><li><strong>Nom d&#39;utilisateur</strong> : Le nom d&#39;affichage que vous avez choisi</li><li><strong>Informations du compte GitHub</strong> : Si vous choisissez de vous connecter via GitHub, nous récupérerons vos informations publiques</li></ul><h3 id="donnees-d-utilisation" tabindex="-1">Données d&#39;utilisation <a class="header-anchor" href="#donnees-d-utilisation" aria-label="Permalink to &quot;Données d&#39;utilisation&quot;">​</a></h3><ul><li><strong>Historique de navigation</strong> : Les pages de tutoriels que vous visitez et les heures de visite</li><li><strong>Comportements d&#39;interaction</strong> : Opérations telles que la copie de code et la navigation entre les chapitres</li><li><strong>Historique de recherche</strong> : Les mots-clés que vous recherchez sur le site</li></ul><h3 id="informations-sur-l-appareil" tabindex="-1">Informations sur l&#39;appareil <a class="header-anchor" href="#informations-sur-l-appareil" aria-label="Permalink to &quot;Informations sur l&#39;appareil&quot;">​</a></h3><ul><li><strong>Type de navigateur</strong> : Chrome, Firefox, Safari, etc.</li><li><strong>Système d&#39;exploitation</strong> : Windows, macOS, Linux, etc.</li><li><strong>Adresse IP</strong> : Utilisée pour la protection de sécurité et l&#39;optimisation régionale</li></ul><h2 id="_2-utilisation-des-informations" tabindex="-1">2. Utilisation des informations <a class="header-anchor" href="#_2-utilisation-des-informations" aria-label="Permalink to &quot;2. Utilisation des informations&quot;">​</a></h2><p>Les informations que nous collectons sont utilisées aux fins suivantes :</p><ul><li><strong>Fourniture du service</strong> : Assurer que vous pouvez accéder et utiliser normalement le contenu des tutoriels</li><li><strong>Expérience personnalisée</strong> : Mémoriser votre progression de lecture et vos préférences</li><li><strong>Amélioration du produit</strong> : Analyser les modèles d&#39;utilisation pour optimiser le contenu et les fonctionnalités</li><li><strong>Sécurité</strong> : Détecter les comportements anormaux et prévenir les abus</li><li><strong>Envoi de notifications</strong> : Envoyer des rappels de mise à jour des tutoriels et des annonces importantes (possibilité de se désabonner)</li></ul><h2 id="_3-partage-et-divulgation-des-informations" tabindex="-1">3. Partage et divulgation des informations <a class="header-anchor" href="#_3-partage-et-divulgation-des-informations" aria-label="Permalink to &quot;3. Partage et divulgation des informations&quot;">​</a></h2><p>Nous ne vendons pas vos informations personnelles. Le partage ne peut avoir lieu que dans les cas suivants :</p><ul><li><strong>Prestataires de services tiers</strong> : Tels que Vercel (hébergement) et Plausible (analyse), qui ne peuvent accéder qu&#39;aux informations nécessaires à l&#39;accomplissement de leurs fonctions</li><li><strong>Exigences légales</strong> : Divulgation conformément aux lois, règlements ou exigences gouvernementales</li><li><strong>Protection des droits</strong> : Situations nécessaires pour protéger les droits d&#39;OpenCodeDocs et des utilisateurs</li></ul><h2 id="_4-stockage-et-securite-des-donnees" tabindex="-1">4. Stockage et sécurité des données <a class="header-anchor" href="#_4-stockage-et-securite-des-donnees" aria-label="Permalink to &quot;4. Stockage et sécurité des données&quot;">​</a></h2><ul><li><strong>Emplacement de stockage</strong> : Les données sont stockées sur des serveurs sécurisés situés aux États-Unis et dans la région Asie-Pacifique</li><li><strong>Mesures de chiffrement</strong> : Les données en transit sont chiffrées avec TLS/SSL, les données sensibles sont stockées avec un chiffrement AES-256</li><li><strong>Contrôle d&#39;accès</strong> : Accès strictement limité du personnel interne aux données</li><li><strong>Durée de conservation</strong> : Après la suppression du compte, les données personnelles seront supprimées dans un délai de 30 jours</li></ul><h2 id="_5-vos-droits" tabindex="-1">5. Vos droits <a class="header-anchor" href="#_5-vos-droits" aria-label="Permalink to &quot;5. Vos droits&quot;">​</a></h2><p>Conformément à la Loi sur la protection des informations personnelles et au RGPD, vous bénéficiez des droits suivants :</p><ul><li><strong>Droit d&#39;accès</strong> : Vous avez le droit de consulter les informations personnelles que nous détenons vous concernant</li><li><strong>Droit de rectification</strong> : Vous avez le droit d&#39;exiger la correction d&#39;informations personnelles inexactes</li><li><strong>Droit à l&#39;effacement</strong> : Vous avez le droit d&#39;exiger la suppression de vos informations personnelles</li><li><strong>Droit à la portabilité</strong> : Vous avez le droit d&#39;exporter vos données dans un format courant</li><li><strong>Droit de retrait du consentement</strong> : Vous avez le droit de retirer à tout moment le consentement précédemment donné</li></ul><p>Si vous souhaitez exercer ces droits, veuillez nous contacter via les coordonnées ci-dessous.</p><h2 id="_6-politique-relative-aux-cookies" tabindex="-1">6. Politique relative aux cookies <a class="header-anchor" href="#_6-politique-relative-aux-cookies" aria-label="Permalink to &quot;6. Politique relative aux cookies&quot;">​</a></h2><p>Nous utilisons les types de cookies suivants :</p><ul><li><strong>Cookies nécessaires</strong> : Maintenir l&#39;état de connexion, mémoriser les préférences linguistiques</li><li><strong>Cookies d&#39;analyse</strong> : Statistiques sur le volume de visites et les modèles d&#39;utilisation (en utilisant Plausible respectueux de la vie privée)</li><li><strong>Cookies publicitaires</strong> : <ul><li>Les fournisseurs tiers, y compris Google, utilisent des cookies pour diffuser des publicités en fonction des visites précédentes de l&#39;utilisateur sur votre site ou sur d&#39;autres sites.</li><li>Google utilise des cookies publicitaires pour permettre à Google et à ses partenaires de diffuser des publicités aux utilisateurs en fonction de leurs visites sur votre site et/ou d&#39;autres sites sur Internet.</li><li>Les utilisateurs peuvent visiter <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google Ad Settings</a> pour désactiver les publicités personnalisées. Alternativement, vous pouvez orienter les utilisateurs vers <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> pour désactiver les cookies de fournisseurs tiers utilisés pour les publicités personnalisées.</li></ul></li></ul><p>Vous pouvez gérer les cookies via les paramètres de votre navigateur. La désactivation des cookies nécessaires peut affecter le fonctionnement normal de certaines fonctionnalités.</p><h2 id="_7-contactez-nous" tabindex="-1">7. Contactez-nous <a class="header-anchor" href="#_7-contactez-nous" aria-label="Permalink to &quot;7. Contactez-nous&quot;">​</a></h2><p>Si vous avez des questions sur cette politique de confidentialité ou si vous souhaitez exercer vos droits sur vos données, veuillez contacter :</p><ul><li><strong>E-mail</strong> : <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Délai de réponse</strong> : Nous répondrons à votre demande dans un délai de 15 jours ouvrables</li></ul>',30)])])}const v=s(n,[["render",r]]);export{m as __pageData,v as default};
